// items: one per row from Google Sheets
const history = items
  .map(i => i.json)
  .filter(r => r.date && r.coverageVolume)
  .map(r => ({
    date: r.date,
    coverageVolume: Number(r.coverageVolume),
    totalResults: Number(r.totalResults || r.coverageVolume),
  }));

return [
  {
    json: {
      history,
    },
  },
];

// Get the "history" array from the first item
const history = items[0].json.history;

// Sum coverageVolume
const totalVolume = history.reduce((sum, entry) => sum + entry.coverageVolume, 0);

// Calculate average
const averageVolume = totalVolume / history.length;

// Return result as a single item
return [
  {
    json: {
      averageCoverageVolume: averageVolume
    }
  }
];
